import type { MyClTx } from '@/services/city-ledger';

export interface FolioRow {
  _rowId: string;
  _raw: MyClTx;
  status: {
    id: string;
    label: string;
    variant: string;
    description: string;
  };
  type: string;
  serviceDate: string;
  bookingNumber: number;
  docNumber: string | null;
  description: string;
  debit: number;
  credit: number;
  balance: number;
}

export function mapClTxToFolioRow(tx: MyClTx): Omit<FolioRow, '_rowId'> {
  const status = tx.IS_LOCKED
    ? { id: 'billed', label: 'Billed', variant: 'success', description: '' }
    : tx.IS_HOLD
      ? { id: 'held', label: 'Held', variant: 'warning', description: '' }
      : { id: 'unbilled', label: 'Unbilled', variant: 'neutral', description: '' };

  return {
    _raw: tx,
    status,
    type: tx.CATEGORY,
    serviceDate: tx.SERVICE_DATE,
    bookingNumber: tx.BOOK_NBR ? Number(tx.BOOK_NBR) : null,
    docNumber: tx.EXTERNAL_REF,
    description: tx.DESCRIPTION,
    debit: tx.DEBIT,
    credit: tx.CREDIT,
    balance: tx.RUNNING_BALANCE,
  };
}

export interface FolioFilters {
  fromDate?: string;
  toDate?: string;
  status?: string;
  search?: string;
}

export interface FolioSummary {
  startingBalance: number;
  totalDebits: number;
  totalCredits: number;
  currentBalance: number;
  unbilledCount: number;
}
